```cpp
// 不定長滑動視窗模板
void slidingWindow(vector<int>& nums) {
    int n = nums.size();
    int left = 0;
    for (int right = 0; right < n; ++right) {
        // 1. 進窗：更新視窗內資料
        // ...

        // 2. 出窗：當不滿足條件時，縮小左邊界
        while (/* 滿足出窗條件 */) {
            // 更新視窗內資料
            left++;
        }

        // 3. 更新答案
        // ...
    }
}
```
